const body = $json.body || $json;
const texto = (body.message || body.texto || '').trim().toLowerCase();
const sessionId = body.sessionId || 'preview-000';

if (!texto) return [];

return [{ json: { tel: sessionId, instancia: 'preview', texto, remoteJid: sessionId } }];

const now = new Date();
const optsTime = { timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit', hour12: false };
const horaAtual = now.toLocaleTimeString('pt-BR', optsTime).substring(0, 5);
const diaBR = new Date(now.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const dias = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 'sab'];
const diaSemana = dias[diaBR.getDay()];

return [{ json: { ...$json, horaAtual, diaSemana } }];

const msgData = $('Calcular Hora').first().json;
const { tel, instancia, texto, horaAtual, diaSemana } = msgData;

const config = $json.config || {};
const produtos = $json.produtos || [];

const horarioAbertura = config['horario_abertura'] || '18:00';
const horarioFechamento = config['horario_fechamento'] || '23:00';
const diasFuncionamento = (config['dias_funcionamento'] || 'ter,qua,qui,sex,sab,dom').split(',');
const msgForaHorario = (config['msg_fora_horario'] || 'Estamos fechados agora!').replace(/\\n/g, '\n');
const msgBoasVindas = (config['msg_boas_vindas'] || 'Olá! Bem-vindo!').replace(/\\n/g, '\n');
const botNome = config['nome_estabelecimento'] || 'Bot';

const aberto = diasFuncionamento.includes(diaSemana) &&
               horaAtual >= horarioAbertura &&
               horaAtual <= horarioFechamento;

let resposta = '';

if (!aberto) {
  return [{ json: { tel, instancia, resposta: msgForaHorario, aberto: false, botNome } }];
}

const saudacoes = ['oi', 'ola', 'bom dia', 'boa tarde', 'boa noite', 'inicio', 'menu', 'start', 'hello', 'hi'];
if (saudacoes.includes(texto) || texto.includes('oi!') || texto.includes('ola!')) {
  resposta = msgBoasVindas + '\n\nComo posso ajudar?\n\n1️⃣ Ver Cardápio\n2️⃣ Fazer Pedido\n3️⃣ Reservar Mesa\n4️⃣ Falar com Atendente\n\nDigite o número da opção.';

} else if (texto === '1' || texto.includes('cardapio') || texto.includes('cardápio') || texto.includes('menu')) {
  if (!produtos || produtos.length === 0) {
    resposta = 'Cardápio temporariamente indisponível. Tente em instantes.';
  } else {
    const porCategoria = {};
    produtos.forEach((item, idx) => {
      const cat = item.categoria || 'Outros';
      if (!porCategoria[cat]) porCategoria[cat] = { emoji: item.emoji || '🍽️', itens: [] };
      porCategoria[cat].itens.push((idx + 1) + '. ' + item.nome + ' — R$ ' + Number(item.preco).toFixed(2));
    });
    let linhas = ['🍣 *Cardápio*\n'];
    for (const [cat, data] of Object.entries(porCategoria)) {
      linhas.push(data.emoji + ' *' + cat + '*');
      linhas.push(...data.itens);
      linhas.push('');
    }
    linhas.push('Digite o *número* do item para escolher, ou *0* para voltar ao menu.');
    resposta = linhas.join('\n');
  }

} else if (texto === '2' || texto.includes('pedido') || texto.includes('pedir')) {
  resposta = '🛒 Vamos montar seu pedido!\n\nDigite *cardápio* para ver os itens e escolha pelo número.';

} else if (texto === '3' || texto.includes('reserva') || texto.includes('reservar') || texto.includes('mesa')) {
  resposta = '📅 *Reserva de Mesa*\n\nPara reservar, informe:\n• Data e horário desejado\n• Número de pessoas\n\nEx: Sábado às 20h para 2 pessoas';

} else if (texto === '4' || texto.includes('atendente') || texto.includes('humano')) {
  resposta = '👤 Conectando com um atendente...\n\nAguarde um momento!';

} else if (texto === '0' || texto === 'sair' || texto === 'cancelar' || texto === 'voltar') {
  resposta = msgBoasVindas + '\n\nComo posso ajudar?\n\n1️⃣ Ver Cardápio\n2️⃣ Fazer Pedido\n3️⃣ Reservar Mesa\n4️⃣ Falar com Atendente';

} else {
  const num = parseInt(texto);
  if (!isNaN(num) && num >= 1 && produtos && num <= produtos.length) {
    const item = produtos[num - 1];
    const emoji = item.emoji || '🍽️';
    resposta = emoji + ' *' + item.nome + '*\nR$ ' + Number(item.preco).toFixed(2) + '\n\nDigite outro número para mais itens, ou *finalizar* para concluir o pedido.';
  } else {
    resposta = 'Não entendi 😅\n\nDigite *menu* para ver as opções.';
  }
}

return [{ json: { tel, instancia, resposta, aberto: true, botNome } }];
